UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior", "Interior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Fomentar un entorno de confianza"], "materiales": ["Pañolin", "Silbato"], "variaciones": "Puede variar las indicaciones que dan los \"árboles\" para que sean determinados sonidos cuando se están acercando.", "recomendaciones": "Procure que el terreno está nivelado y libre de obstáculos que impidan un caminar seguro de los \"jardineros\".", "justificacion_areas": "Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElJardinero.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Practicando la empatía y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto": "Mantengo mi opinión cuando estoy convencida que es correcta.", "unidad": "Compañía", "como_se_cumple": "Practicando la empatía y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "a4060c60-7ce9-425b-bf2a-76941a689937", "area": "Afectividad", "texto": "Escucho las opiniones de los demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Tropa", "como_se_cumple": "Practicando la empatía y la asertividad en las relaciones interpersonales de patrulla en El Jardinero."}, {"id": "4ade9c82-6b0d-4a44-8bc6-2eb47a011ffb", "area": "Afectividad", "texto": "Digo lo que