UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acción", "Trabajo en equipo"], "materiales": ["Cartulina", "Cinta Adhesiva", "Lápiz", "Papel", "Papel craft", "Plumón"], "variaciones": "La actividad puede variar cambiando la clave en la que se entregan las frases o agregando una dificultad en la salida de los jugadores cuando estén en la fila para poner la palabra en el texto, por ejemplo con un <a href=\"https://nuamana.com/nuanew/actividades/juegos/cuerpo-a-tierra/\" target=\"_blank\" rel=\"noopener\">cuerpo a tierra</a> o borrachitos, etc.", "recomendaciones": "Procure reforzar adecuadamente el contenido del texto, que es lo más importante del desarrollo de la actividad, haciendo los énfasis adecuados cuando se hace el repaso final.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CompletaLaOracion.png", "objetivos_educativos": [{"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y rápidas para resolver los acertijos o enigmas mentales de Completa la oración."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y rápidas para resolver los acertijos o enigmas mentales de Completa la oración."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee