UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Exterior", "Interior", "Sala"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Desarrollar la capacidad cognitiva", "Estimular la agilidad", "Estimular la agilidad mental"], "materiales": ["Dados", "Guantes de cocina", "Regalos envueltos"], "variaciones": "Una variación puede ser hacer lo mismo con los ojos vendados, mientras que la o el jugador que le seguiría en turno le indica el resultado de los dados.", "recomendaciones": "El o la moderadora debe estar atento a que los jugadores no lancen los dados más de una vez o indique un resultado que no corresponde para tener el regalo antes de tiempo.\r\n\r\nDe la misma manera se debe poner especial atención en la forma en que se entregan los regalos y guantes de un jugador a otro, debe ser rápido pero con precaución de que no haya un golpe.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_regalosYGuantes.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisión y rol de Regalos y Guantes."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisión y rol de Regalos y Guantes."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Regalos y Guantes."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Regalos y Guantes."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Regalos y Guantes, aceptando con alegría la victoria o la derrota."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Regalos y Guantes, aceptando con alegría la victoria o la derrota."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Regalos y Guantes."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Regalos y Guantes."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Regalos y Guantes."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Regalos y Guantes."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Regalos y Guantes."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Regalos y Guantes."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y rápidas para resolver los acertijos o enigmas mentales de Regalos y Guantes."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las anécdotas y aventuras que hemos tenido en la Manada.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y rápidas para resolver los acertijos o enigmas mentales de Regalos y Guantes."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Regalos y Guantes."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Regalos y Guantes."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Regalos y Guantes."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Regalos y Guantes."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Regalos y Guantes."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Regalos y Guantes."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Regalos y Guantes."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Regalos y Guantes."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Regalos y Guantes."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Regalos y Guantes."}]}'::jsonb WHERE id = '595e2d35-4636-4f20-9815-fffe4f641928';

UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "12 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada"], "objetivos": ["Aprender elementos Básicos de Primeros Auxilios", "Aprendizaje por la acción", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "En lugar de utilizar una persona como \"paciente\" en el traslado puede utilizar otro elemento que requiera mantener cierto equilibrio para que no se caiga.", "recomendaciones": "Procure hacer énfasis en que la actividad no es sobre llegar primero a la meta, sino sobre que \"paciente\" llega en mejor condición a la meta.\r\n\r\nMuestre el estado y condición del terreno para hacer énfasis de la misma manera en la importancia de la seguridad en la actividad.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeCamillas.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de camillas."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de camillas."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de camillas."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de camillas."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Carrera de camillas."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Carrera de camillas."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Carrera de camillas."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Carrera de camillas."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Carrera de camillas."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Carrera de camillas."}]}'::jsonb WHERE id = 'fa3fe65c-fb44-46a6-9a27-6ea8bf72e246';

UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "20 minutos", "unidades": ["compañía", "tropa", "avanzada", "clan"], "objetivos": ["Aprendizaje por la acción", "Reforzar el conocimiento"], "materiales": ["Preguntas", "Silbato"], "variaciones": "Puede hacer el juego sin saltos, sólo con el cuerpo a tierra correr y responder la pregunta, cambiando de esta manera el formato de quien es el que gana, siendo la medición en este caso por quien respondió más preguntas correctas.", "recomendaciones": "<ul>\r\n \t<li>Al momento de realizar el cuerpo a tierra, tener énfasis en el cuidado del cuerpo de los demás para no pisarlos.</li>\r\n \t<li>Si la o el participante no puede tirarse al suelo, considerar opciones o variaciones para que puede agacharse o moverse de otra manera si a así se requiere.</li>\r\n \t<li>Preguntas e historia estarán en archivos de descargas y se llevarán impresos para la actividad.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDelSaber.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera del Saber."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera del Saber."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera del Saber."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera del Saber."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Carrera del Saber."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Carrera del Saber."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Carrera del Saber."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Carrera del Saber."}, {"id": "857f21bc-db3c