UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Aprendizaje por la acción", "Desarrollar la motricidad"], "materiales": ["Fósforos"], "variaciones": "Puede variar la actividad utilizando una vela que tendrá un efecto similar.", "recomendaciones": "Procure tomar todas la precauciones de seguridad posibles, primero no realice la actividad en un área boscosa, idealmente sólo realícela en un área cubierta por cemento y siempre tenga agua a la mano para evitar un incendio.\r\n\r\nHaga las indicaciones necesarias a los participantes sobre le el cuidado y los peligros del fuego.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_carreraDeFosforos.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Carrera de Fósforos."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Carrera de Fósforos."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de Fósforos."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de Fósforos."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de Fósforos."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Carrera de Fósforos."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en Carrera de Fósforos."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en Carrera de Fósforos."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Carrera de Fósforos."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Carrera de Fósforos."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Carrera de Fósforos."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Carrera de Fósforos."}]}'::jsonb WHERE id = '25e55b5d-8f37-40af-9d43-ba0c4f3b74fd';

UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "espiritualidad"], "lugares": ["Exterior", "Interior"], "cantidad": "individual", "duracion": "20 minutos", "unidades": ["avanzada", "clan"], "descargas": [{"url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.pdf", "nombre": "Documento Adjunto - Hoja de Epitafio"}], "objetivos": ["Estimular el pensamiento crítico", "Estimular la reflexión"], "materiales": ["Lápiz", "Papel"], "variaciones": "Puede agregar una temática particular a los epitafios, por ejemplo, haciendo la pregunta ¿Qué diría su epitafio si usted fuera Bombero? o agregando cualquier otra circunstancia específica para ayudar a reflexionar sobre un trabajo en particular.", "recomendaciones": "Trate de generar o esperar a que se de el ambiente reflexivo adecuado para la actividad, esta es una actividad de introspección para jóvenes que en algunos casos puede generar sensibilidades.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Conecta a los participantes con la creación y el sentido de trascendencia espiritual de la hermandad scout.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElEpitafio.png", "objetivos_educativos": [{"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de El Epitafio."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de El Epitafio."}, {"id": "c165a639-f87a-4f6c-a637-69894848b507", "area": "Espiritualidad", "texto": "Respeto y cuido la naturaleza porque me siento responsable de la obra creadora de Dios.", "unidad": "Avanzada", "como_se_cumple": "Coherentemente integrando principios espirituales scout en sus reflexiones cotidianas tras El Epitafio."}, {"id": "0a9a9dac-0b1c-4f11-8600-291de10b1b95", "area": "Espiritualidad", "texto": "Busco siempre a Dios en forma personal y comunitaria, aprendiendo a reconocerlo en los hombres y en la Creación.", "unidad": "Clan", "como_se_cumple": "Coherentemente integrando principios espirituales scout en sus reflexiones cotidianas tras El Epitafio."}]}'::jsonb WHERE id = '18ae9052-19bf-48ca-89a3-c34f0081e7ca';

UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "05 participantes", "duracion": "15 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aumentar el conocimiento de las limitantes físicas", "Crear un ambiente de distensión", "Desfogue de Energías", "Refuerzo de habilidades físicas"], "materiales": ["Sin Materiales"], "variaciones": "Se puede hacer por equipos, donde gana el equipo que conserva más esquinas cuando termina el juego, sin embargo, para ello es necesario que haya más participantes en el centro.", "recomendaciones": "Tenga cuidado de elegir un terreno nivelado y de hacer énfasis en el respeto por los demás para que no se empujen a la hora de ver quién llega primero a tomar una esquina.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_TomaUnaEsquina.png", "objetivos_educativos": [{"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Toma una Esquina."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Toma una Esquina."}, {"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercit