UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "carácter", "sociabilidad"], "lugares": ["Campo Abierto", "Exterior"], "cantidad": "04 participantes", "duracion": "15 minutos", "unidades": ["compañía", "tropa"], "objetivos": ["Crear un ambiente de distensión", "Estimular el liderazgo", "Fomentar un entorno de confianza", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Existe una versión en parejas, donde se turnan en el trayecto de ida y de vuelta, esta versión esta más enfocada en generar lazos o relaciones entre las y los participantes más que en reforzar un liderazgo.", "recomendaciones": "Procure que el terreno no este muy accidentado para evitar caídas y observe meticulosamente el proceso para evaluar el liderazgo del guía de patrulla.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_ElLazarilloEnPatrulla.png", "objetivos_educativos": [{"id": "818d8a25-549b-4e01-a830-e50d73e39025", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemorizan.", "unidad": "Compañía", "como_se_cumple": "Canalizando emociones difíciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "67a2f0fa-9b1e-4b7b-bda2-e25696c87898", "area": "Afectividad", "texto": "Trato de dominar mis reacciones, aún en situaciones difíciles o inesperadas.", "unidad": "Compañía", "como_se_cumple": "Canalizando emociones difíciles de incertidumbre o temor al andar a ciegas en El Lazarillo en Patrulla."}, {"id": "03ccaf4c-03c4-42a8-b311-47fef60f204c", "area": "Afectividad", "texto": "Me doy cuenta y puedo hablar de las cosas que me atemoriza