 "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Bomba de tiempo."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Bomba de tiempo."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Bomba de tiempo."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Bomba de tiempo."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Bomba de tiempo."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Bomba de tiempo."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Bomba de tiempo."}, {"id": "9f30f035-9179-4ac4-acfb-bea0e169e97a", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Bomba de tiempo."}, {"id": "49ae6ac6-be8f-4f2c-8b3e-6711d041181f", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Bomba de tiempo."}, {"id": "cf530cf9-73a6-4423-a075-79be433fe96c", "area": "Creatividad", "texto": "Propongo temas para discutir en mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales en Bomba de tiempo."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Bomba de tiempo."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Bomba de tiempo."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Bomba de tiempo."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Bomba de tiempo."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Bomba de tiempo."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Bomba de tiempo."}]}'::jsonb WHERE id = '6fb66f20-f92c-451d-9070-61f0251076fe';

UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "individual", "duracion": "15 minutos", "unidades": ["avanzada", "clan", "compañía", "manada", "tropa"], "objetivos": ["Conocer las capacidades corporales", "Crear un ambiente de distensión", "Estrategia y planificación", "Promover la elaboración de estrategias"], "materiales": ["Pañolin"], "variaciones": "<strong>Formal</strong>: Esta variación es uno contra uno, en un círculo formado en el suelo, además de perder el pañolin en este caso también se puede perder por salir del círculo. No se puede quitar el pañolin si el oponente está caído en el suelo o de espalda.\r\n\r\n<strong>En equipo</strong>: Los equipos se enfrentan en una especie de cacería y cada vez que dos participantes se encuentran harán una pelea de pañolines, quien pierda entregara su pañolin que será una vida adicional para quién ganó.\r\n\r\n<strong>Flechazo</strong>: También se hace en equipo, sin embargo, habrá un equipo en cada extremo del campo y a la señal cada equipo cruzara el campo para ubicarse donde se encuentra el equipo contrario, en el cruce entre ambos equipos se pueden quitar los pañolines al pasar y sin ser necesariamente uno contra uno, en este caso se puede aprovechar cualquier distracción del oponente para quitarle su pañolin.\r\n\r\n<strong>Ojos Vendados</strong>: Se hace con los ojos vendados y siguiendo las instrucciones del resto de su equipo.\r\n\r\n<strong>Al hombro</strong>: se amarra el pañolin en el hombro con un nudo simple de sacar al tirar de una de las puntas.\r\n\r\n<strong>Al tobillo</strong>: mismo anterior pero el pañolin va amarrado en el tobillo o la pierna\r\n\r\n<strong>A caballo</strong>: Se hace en parejas donde uno se sube arriba del otro, el o la \"caballo\" es quien está debajo y sólo se preocupa de desplazarse y evitar dejar el pañolin del \"jinete\" a merced de la otra pareja, la o el \"jinete\" que está arriba lleva el pañolin y tiene que cuidar su pañolin y tratar de quitar el pañolin contrario.\r\n\r\n<strong>De dragones</strong>: se hace en equipo, en filas tomados de la cintura, la o el primero de la fila debe tratar de quitar el pañolin, y el último de cada fila de protegerlo, no se pueden soltar las filas, si se sueltan pierden.\r\n\r\nEn el barro, en la nieve, saltando en un pie, sosteniendo algo, con una mano, etc, etc, etc.", "recomendaciones": "Procure indicar la importancia sobre el cuidado del cuerpo, y elegir un terreno adecuado para que no ocurran accidentes por golpes, caídas o tropiezos.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_peleaPanolines.png", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Pelea de pañolines."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convivo constantemente en la naturaleza y participo en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Pelea de pañolines."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Pelea de pañolines."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Pelea de pañolines."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso rápido y coordinando sus movimientos con sus compañeros durante la dinámica de Pelea de pañolines."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso rápido y coordinando sus movimientos con sus compañeros durante la dinámica de Pelea de pañolines."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Pelea de pañolines."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Pelea de pañolines."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Pelea de pañolines."}, {"id": "ef75fb