UPDATE public.articulos SET metadata = '{"areas": ["carácter", "corporalidad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "20 minutos", "unidades": ["compañía", "manada", "tropa"], "objetivos": ["Aprender a seguir instrucciones", "Trabajo en equipo"], "materiales": ["Agua", "Botella"], "variaciones": "Una variación de esta actividad se puede hacer cambiando las botella por otro recipiente, por ejemplo una cubeta, de esta forma al tener la boquilla más abierta que una botella es más probable que caiga agua en el traslado del contenedor en lugar de la transferencia del líquido.", "recomendaciones": "Procure evitar esta actividad durante el invierno para que no se mojen los participantes en un mal clima.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeBotellasConAgua.png", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de botellas con agua."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de botellas con agua."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "