UPDATE public.articulos SET metadata = '{"areas": ["afectividad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "25 minutos", "unidades": ["compañía", "tropa"], "descargas": [{"url": "https://dl.dafont.com/dl/?f=morse", "nombre": "Fuente Morse (Dafont)"}], "objetivos": ["Aprender criptografía", "Aprendizaje por la acción", "Estimular el pensamiento lógico", "Trabajo en equipo"], "materiales": ["Lápiz", "Papel", "Pañolin"], "variaciones": "En lugar de vendarse los ojos los participantes y ser guiados a viva voz hasta los mensajes, también se puede reemplazar esto por un <a href=\"https://nuamana.cl/actividades/juegos/cuerpo-a-tierra/\" target=\"_blank\" rel=\"noopener\">cuerpo a tierra</a>, u otra carrera que los lleve desde un extremo al otro del campo.\r\n\r\nDe la misma manera se puede reemplazar el código morse por otra clave, para aumentar o disminuir la dificultad.", "recomendaciones": "Procure hacer la actividad en un lugar plano y despejados, sin riesgos de caídas por tropiezos o golpes en la cabeza por algo en altura.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Desarrolla el autoconocimiento, la confianza grupal y la empatía en las interacciones del juego. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_LeyConClaveMorse.png", "objetivos_educativos": [{"id": "2f8359db-221e-4a64-b2df-2b3e7b74a2db", "area": "Afectividad", "texto": "Escucho las opiniones de las demás personas y si no estoy de acuerdo lo digo con respeto.", "unidad": "Compañía", "como_se_cumple": "Practicando la empatía y la asertividad en las relaciones interpersonales de patrulla en Ley con clave morse."}, {"id": "3621f4ae-1316-4b3e-8682-3e3c9ad381a7", "area": "Afectividad", "texto":