UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad", "sociabilidad"], "lugares": ["Campo delimitado", "Exterior"], "cantidad": "06 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Aprender a seguir instrucciones", "Aumentar el conocimiento de las limitantes físicas", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Una variación es que en lugar de gritar desde el otro lado del campo las instrucciones puede ir una compañera o compañero de equipo al lado del participante que está vendada o vendado para darle las indicaciones.", "recomendaciones": "<ul>\r\n \t<li>Ponga énfasis en el cuidado de la jugadora o jugador cuando le den instrucciones para evitar accidentes.</li>\r\n \t<li>Procure que el terreno sea un terreno parejo para evitar que las y los participantes tropiecen y se caigan.</li>\r\n \t<li>Indique que no es necesario correr y que se debe primero saber que se esta dando un paso seguro.</li>\r\n</ul>", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_RelevosCiegos.png", "objetivos_educativos": [{"id": "36d989b6-30dd-434a-874a-70a993ed0bec", "area": "Corporalidad", "texto": "Conozco las principales enfermedades que me pueden dar y por qué.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisión visomotora y el control de su cuerpo en los desafíos corporales de Relevos Ciegos."}, {"id": "6467298d-fe2b-4920-9b9a-e3524e4b2aef", "area": "Corporalidad", "texto": "Sé en qué lugar de mi cuerpo están ubicados los órganos más importantes.", "unidad": "Manada", "como_se_cumple": "Ejercitando la precisión visomotora y el control de su cuerpo en los desafíos corporales de Relevos Ciegos."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta de los cambios que se están produciendo en mi cuerpo.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Relevos Ciegos."}, {"id": "57887da4-c70e-45bc-bdfb-f79db513a89c", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Compañía", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Relevos Ciegos."}, {"id": "8cae916f-5e67-4697-b3cd-c59b5c7d1439", "area": "Corporalidad", "texto": "Trato de evitar situaciones que puedan dañar mi salud y la de mis compañeros.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Relevos Ciegos."}, {"id": "68add558-4b03-4105-b00d-e7f2ead6ac23", "area": "Corporalidad", "texto": "Sé qué hacer frente a una enfermedad o accidente.", "unidad": "Tropa", "como_se_cumple": "Desarrollando destrezas corporales finas y regulando su respiración ante la tensión visomotora de Relevos Ciegos."}, {"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de Relevos Ciegos."}, {"id": "ec280dd0-2d80-4b84-86ad-2d362da14886", "area": "Creatividad", "texto": "Me gusta participar en juegos de observación.", "unidad": "Manada", "como_se_cumple": "Proponiendo ideas originales y rápidas para resolver los acertijos o enigmas mentales de Relevos Ciegos."}, {"id": "418f2b77-f15b-405a-95bd-8033c0b6a4c2", "area": "Creatividad", "texto": "Puedo contar con detalles las a