UPDATE public.articulos SET metadata = '{"areas": ["creatividad", "sociabilidad"], "lugares": ["Bosque", "Cerro", "Exterior", "Interior", "Montaña", "Río"], "cantidad": "04 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan"], "objetivos": ["Estimular la creatividad", "Fomentar el desarrollo del criterio", "Trabajo en equipo"], "materiales": ["Objetos Varios"], "variaciones": "Se puede variar en la cantidad de tiempo establecido, cantidad de participantes por equipo, cantidad de objetos a ser utilizados para lograr la meta, tipos de objetos que NO pueden ser utilizados, el tamaño del lugar en donde se realizará la actividad.", "recomendaciones": "Se requiere precaución a la hora de ocupar los objetos encontrados por los participantes, asegurarse de que estos no sean peligrosos en su uso, o quienes lo ocupen tengan manejo adecuado de estos. También precaución con el terreno en donde se realiza, evitando que existan elementos que puedan dañar físicamente a algún participante", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_macgyverPreparadoParaLaAventura.png", "objetivos_educativos": [{"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en MacGyver Preparado para la Aventura."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Uno los conocimientos teórico y práctico mediante la aplicación constante de mis habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en MacGyver Preparado para la Aventura."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en MacGyver Preparado para la Aventura."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumplo las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en MacGyver Preparado para la Aventura."}]}'::jsonb WHERE id = 'afebb91a-f5bc-49b1-8d00-e8bcf555b4ee';

UPDATE public.articulos SET metadata = '{"areas": ["carácter"], "lugares": ["Campo delimitado", "Exterior", "Interior", "Sala"], "cantidad": "02 participantes", "duracion": "15 minutos", "unidades": ["manada", "compañía", "tropa", "avanzada"], "objetivos": ["Conocer a los demás", "Estimular el liderazgo"], "materiales": ["Sin Materiales"], "variaciones": "", "recomendaciones": "Al momento de evaluar la justificación evalúe a cada participante en su justo merito y no permita que hayan agresiones emocionales hacia las y los participantes, idealmente base la evaluación en la calidad de la justificación y sea suave en como lo dice.", "justificacion_areas": "Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/Actividad_CarreraDeLiderazgo.png", "objetivos_educativos": [{"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de Liderazgo, aceptando con alegría la victoria o la derrota."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de Liderazgo, aceptando con alegría la victoria o la derrota."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de Liderazgo."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra