UPDATE public.articulos SET metadata = '{"areas": ["carácter", "creatividad", "sociabilidad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "10 participantes", "duracion": "30 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Fomentar las relaciones interpersonales", "Promover la elaboración de estrategias", "Trabajo en equipo"], "materiales": ["Pañolin"], "variaciones": "Se puede instalar una ¿?Zona de los Dioses¿? por la que todos tendrán que pasar cada vez cuando vayan a robar y cuando vuelvan con lo robado. Para controlar el flujo de pérdida del tesoro, en esta zona se pueden jugar la pieza de tesoro con una pelea de pañolines contra el jugador.", "recomendaciones": "Procure hacer énfasis en la seguridad sobre el terreno de juego y que pisen con cuidado a la hora de desplazarse por el área de juego.", "justificacion_areas": "Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_protegiendoLasBases.png", "objetivos_educativos": [{"id": "1d9d6751-4ab1-45db-9999-3f18606b4909", "area": "Carácter", "texto": "Soy fiel a la palabra dada.", "unidad": "Avanzada", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisión y rol de Protegiendo las bases."}, {"id": "770a8ff3-7bb8-45dd-b114-5ae1069eff62", "area": "Carácter", "texto": "Actúo consecuentemente con los valores que me inspiran.", "unidad": "Clan", "como_se_cumple": "Actuando consecuentemente con sus principios y valores individuales en cada decisión y rol de Protegiendo las bases."}, {"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Protegiendo las bases."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Protegiendo las bases."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Protegiendo las bases."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Protegiendo las bases."}, {"id": "3cdf4b56-b55f-4878-b3fa-da32a7200ca4", "area": "Creatividad", "texto": "Soy capaz de sintetizar, criticar, proponer y apreciar las opiniones de los demás.", "unidad": "Avanzada", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Protegiendo las bases."}, {"id": "ef75fbed-4a6d-49ea-bfab-f2952415e1a0", "area": "Creatividad", "texto": "Actúo con agilidad mental ante las situaciones más diversas, desarrollando mi capacidad de pensar, innovar y aventurar.", "unidad": "Clan", "como_se_cumple": "Demostrando agilidad mental y pensamiento crítico inmediato para liderar la resolución estratégica de Protegiendo las bases."}, {"id": "e1b7276f-4fd2-4c39-a32a-bd7fadbee702", "area": "Creatividad", "texto": "Doy mi opinión sobre las cosas que me pasan.", "unidad": "Compañía", "como_se_cumple": "Analizando el escenario táctico del juego de forma ágil para proponer alternativas mentales e