UPDATE public.articulos SET metadata = '{"areas": ["corporalidad", "creatividad"], "lugares": ["Bosque", "Campo delimitado", "Exterior"], "cantidad": "04 participantes", "duracion": "45 minutos", "unidades": ["avanzada", "clan", "compañía", "tropa"], "objetivos": ["Desarrollar la motricidad", "Estimular la observación", "Promover la elaboración de estrategias"], "materiales": ["Linterna"], "variaciones": "Una variación puede ser eliminar a las y los participantes cuando son descubiertos al avanzar.", "recomendaciones": "Tenga en consideración la iluminación en el lugar a la hora de jugar, prefiera un área boscosa para facilitar la huida de los prisioneros o un claro para dificultarla.\r\n\r\nHaga las recomendaciones de seguridad necesarias para que caminen con cuidado en un terreno sin iluminación.", "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas Técnicos o enigmas.", "imagen_destacada_url": "https://raw.githubusercontent.com/claudiomateluna/nua_mana/gh-pages/uploads/actividad_ElGuardiaYLosPrisioneros.png", "objetivos_educativos": [{"id": "05f42879-f5f5-40c4-bed6-c577bf61340a", "area": "Corporalidad", "texto": "Cuido mi salud y mantengo hábitos que la protegen.", "unidad": "Avanzada", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de El guardia y los prisioneros."}, {"id": "69fff91f-a493-483d-92d6-8319700236c2", "area": "Corporalidad", "texto": "Conozco los procesos biológicos que regulan mi organismo, protejo mi salud, acepto mis posibilidades físicas y oriento mis impulsos y fuerzas.", "unidad": "Clan", "como_se_cumple": "Aceptando sus capacidades físicas y perfeccionando el control psicomotor durante el desarrollo de El guardia y los prisioneros."}, {"id": "705b686a-8374-467a-b871-f6470f0d58ae", "area": "Corporalidad", "texto": "Me doy cuenta